const asyncTask = new Promise((resolve, reject) => {
  setTimeout(() => {
    reject(new Error('Promise rejected!'));
  }, 500);
});

// Handling rejection with .catch()
asyncTask.catch(error => {
  console.error('Caught promise rejection:', error.message);
});

