fetchData();

interface User {
  id: string;
  name: string;
  email: string;
  isActive: boolean;
}

const newUser: User = {
  id: "123",
  name: "Alice",
  email: "alice@example.com",
  isActive: true,
};

type Role = "admin" | "editor" | "viewer";

type UserWithRole = User & { role: Role };

const user: UserWithRole = {
  id: "456",
  name: "Bob",
  email: "bob@example.com",
  isActive: false,
  role: "admin",
};

interface Product {
  id: string;
  name: string;
  price: number;
}

interface DigitalProduct extends Product {
  fileSizeMB: number;
  downloadUrl: string;
}

interface PhysicalProduct extends Product {
  weightKg: number;
  shippingCost: number;
}

const ebook: DigitalProduct = {
  id: "001",
  name: "Learn TypeScript",
  price: 29.99,
  fileSizeMB: 5,
  downloadUrl: "https://example.com/download/ebook",
};

// Partial allows making all properties optional
const updateUser: Partial<User> = {
  email: "newemail@example.com",
};

// Pick selects specific keys
type UserContactInfo = Pick<User, "email" | "name">;

const contact: UserContactInfo = {
  email: "contact@example.com",
  name: "Contact Name",
};

interface ImmutableUser {
  readonly id: string;
  readonly name: string;
  readonly email: string;
}

const immutableUser: ImmutableUser = {
  id: "789",
  name: "Charlie",
  email: "charlie@example.com",
};

